var E=[new KV('','')];
var BASE='https://asurascans.com';
var PLACEHOLDER='https://asurascans.com/images/default-cover.webp';
function saved(){return document.getElementById('ketsu-final-data');}
function setFinal(obj){var el=saved();if(el){el.textContent=JSON.stringify(obj);}}
function req(url){return new MR(url,'GET',E,null);}
function imgReq(url){return new MR(url,'GET',[new KV('Referer',BASE + '/')],null);}
function clean(s){var t=document.createElement('textarea');t.innerHTML=(s||'');return (t.value||'').replace(/\s+/g,' ').trim();}
function abs(u){if(!u){return '';}if(u.indexOf('http')===0){return u;}if(u.charAt(0)==='/'){return BASE+u;}return BASE+'/'+u;}
function metaContent(sel){var m=document.querySelector(sel);return m?clean(m.getAttribute('content')):'';}
function meta(){try{return JSON.parse((saved()&&saved().textContent)||'{}');}catch(e){return {};}}
function currentUrl(){var m=meta();return (m&&m.request&&m.request.url)||location.href||BASE;}
function unique(arr){var seen={};var out=[];arr.forEach(function(x){if(x&&!seen[x]){seen[x]=true;out.push(x);}});return out;}
function pageTitle(){return (metaContent('meta[property="og:title"]')||clean(document.title)||'').replace(' | Asura Scans','');}
function makeCard(a){
  var href=abs(a.getAttribute('href'));
  if(!href||href.indexOf('/chapter/')>-1){return null;}
  var box=a.closest('.series-card')||a.closest('[class*="slide"]')||a.parentElement||a;
  var img=(box&&box.querySelector('img'))||a.querySelector('img');
  var title=clean((box&&box.querySelector('h3')&&box.querySelector('h3').textContent)||(img&&img.getAttribute('alt'))||a.textContent);
  if(!title||title.length<2||title==='Asura Scans'){return null;}
  var cover=img?(img.getAttribute('src')||img.getAttribute('data-src')||img.getAttribute('data-full-src')):'';
  var boxText=clean((box&&box.textContent)||'');
  var st=(boxText.match(/\b(ongoing|completed)\b/i)||[])[1]||'';
  st=st?st.charAt(0).toUpperCase()+st.slice(1).toLowerCase():'';
  return new Data(imgReq(abs(cover)||PLACEHOLDER),title,'',st,st,'','',false,req(href),false);
}
function collectCards(root,limit){
  var seen={};
  var cards=[];
  (root||document).querySelectorAll('a[href*="/comics/"]').forEach(function(a){
    var href=abs(a.getAttribute('href'));
    if(seen[href]){return;}
    var c=makeCard(a);
    if(c){seen[href]=true;cards.push(c);}
  });
  return cards.slice(0,limit||30);
}

function headingText(h){return clean(h.textContent).toLowerCase();}
function sectionRootFor(h){
  var n=h;
  for(var i=0;i<6&&n;i++){
    if(n.querySelectorAll&&n.querySelectorAll('a[href*="/comics/"]').length>0){return n;}
    n=n.parentElement;
  }
  return h.parentElement||document;
}
function cardsNearHeading(names,limit){
  var hs=document.querySelectorAll('h1,h2,h3');
  for(var i=0;i<hs.length;i++){
    var tx=headingText(hs[i]);
    for(var j=0;j<names.length;j++){
      if(tx.indexOf(names[j])>-1){
        var cards=collectCards(sectionRootFor(hs[i]),limit);
        if(cards.length>0){return cards;}
      }
    }
  }
  return [];
}
var output=[];
var trending=cardsNearHeading(['trending'],20);
var latest=cardsNearHeading(['latest','updated'],30);
var popular=cardsNearHeading(['popular'],20);
var all=collectCards(document,40);
if(trending.length===0){trending=all.slice(0,12);}
if(latest.length===0){latest=all.slice(12,30);}
if(popular.length<8){popular=all.slice(0,24);}
output.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Trending Today',true),null,trending));
output.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Latest Updates',true),null,latest));
output.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Popular',true),null,popular));
if(all.length===0){output=[new Output('wide7','vertical','wideFull','',new Section('AsuraScans',true),null,[new Data(imgReq(PLACEHOLDER),'No results','AsuraScans layout may have changed.','','','','',false,req(BASE),false)])];}
setFinal(new MainPage(req(''),new Extra([new Commands('',E)],E),new JC(true,false,''),output));
} catch(e) {
setFinal(new MainPage(req(''),new Extra([new Commands('',E)],E),new JC(true,false,''),[new Output('wide7','vertical','wideFull','',new Section('Error',true),null,[new Data(imgReq(PLACEHOLDER),'Main page error',e.message,'','','','',false,req(BASE),false)])]));
}

