function decodeHtml(s){var t=document.createElement('textarea');t.innerHTML=s||'';return t.value||'';}
var url=currentUrl();
var title=pageTitle()||clean(document.querySelector('h1')&&document.querySelector('h1').textContent)||'AsuraScan Title';
var cover=metaContent('meta[property="og:image"]')||((document.querySelector('[data-full-src]')||{}).getAttribute&&document.querySelector('[data-full-src]').getAttribute('data-full-src'))||PLACEHOLDER;
var genres=[];
var status='';
var type='Manhwa';
var episodeCount=0;
var html=document.documentElement.innerHTML||'';
var sm=html.match(/&quot;status&quot;:\[0,&quot;([^&]+)&quot;\]/);if(sm){status=cap(sm[1]);}
var tm=html.match(/&quot;type&quot;:\[0,&quot;([^&]+)&quot;\]/);if(tm){type=cap(tm[1]);}
document.querySelectorAll('script[type="application/ld+json"]').forEach(function(s){
  try{
    var j=JSON.parse(s.textContent||'{}');
    if(j.genre&&genres.length===0){genres=Array.isArray(j.genre)?j.genre:[j.genre];}
    if(j.articleSection&&genres.length===0){genres=String(j.articleSection).split(',').map(function(x){return clean(x);}).filter(Boolean);}
    if(j.numberOfEpisodes){episodeCount=j.numberOfEpisodes;}
    if(j.name&&(!title||title==='AsuraScan Title')){title=clean(j.name);}
    if(j.image){cover=(typeof j.image==='string')?j.image:(j.image.url||cover);}
  }catch(e){}
});
if(genres.length===0){
  var gm=html.match(/&quot;genres&quot;:\[1,\[(.*?)\]\]/);
  if(gm){
    var names=gm[1].match(/&quot;name&quot;:\[0,&quot;([^&]+)&quot;\]/g)||[];
    names.forEach(function(x){var m=x.match(/&quot;name&quot;:\[0,&quot;([^&]+)&quot;\]/);if(m){genres.push(decodeHtml(m[1]));}});
  }
}
if(!status){
  var statusNodes=[];
  document.querySelectorAll('span,div').forEach(function(el){var tx=clean(el.textContent);if(/^(ongoing|completed)$/i.test(tx)){statusNodes.push(cap(tx));}});
  if(statusNodes.length){status=statusNodes[0];}
}
var chapterMap={};
document.querySelectorAll('a[href*="/chapter/"]').forEach(function(a){
  var href=abs(a.getAttribute('href'));
  var m=href.match(/\/chapter\/([0-9]+(?:\.[0-9]+)?)/);
  if(!m||chapterMap[href]){return;}
  var num=parseFloat(m[1]);
  chapterMap[href]={num:num,chapter:new Chapter('Chapter '+m[1],req(href),false)};
});
var chapters=Object.keys(chapterMap).map(function(k){return chapterMap[k];}).sort(function(a,b){return a.num-b.num;}).map(function(x){return x.chapter;});
if(chapters.length===0){chapters=[new Chapter('No chapters found',req(url),false)];}
if(!episodeCount){episodeCount=chapters.length;}
var countLabel=episodeCount?episodeCount+' chapters':chapters.length+' chapters';
var output=new InfoOutput(imgReq(cover),title,req(url),'',genres,status,type,countLabel,'',chapters);
